/**
 * Represents the pixel location in image space, where (0, 0) corresponds to the center of the upper left pixel.
 *
 * @since 5.0
 */
export interface LocationInImageSpace {
  /**
   * The row the pixel location.
   *
   * @since 5.0
   */
  x: number;
  /**
   * The column the pixel location.
   *
   * @since 5.0
   */
  y: number;
}